import React, { useEffect, useState } from "react";
import { supabase } from "../../lib/supabase";
import { useAuth } from "../../hooks/useAuth";
import { SponsorshipPackage } from "../../lib/types";
import { loadPackages } from "../../lib/queries";

export function PackageManager() {
  const { sponsorId, loading: authLoading } = useAuth();
  const [packages, setPackages] = useState<SponsorshipPackage[]>([]);
  const [loading, setLoading] = useState(true);
  const [newName, setNewName] = useState("");
  const [newDescription, setNewDescription] = useState("");
  const [adding, setAdding] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (authLoading) return;
    async function load() {
      if (!sponsorId) {
        setLoading(false);
        return;
      }
      setPackages(await loadPackages(sponsorId));
      setLoading(false);
    }
    load();
  }, [authLoading, sponsorId]);

  async function handleAdd(event: React.SyntheticEvent) {
    event.preventDefault();
    if (!sponsorId || !newName.trim()) return;
    setError(null);
    setAdding(true);

    const result = await supabase.from("sponsorship_packages").insert({
      sponsor_id: sponsorId,
      name: newName.trim(),
      description: newDescription.trim() || null,
    } as any);

    if (result.error) {
      setError(result.error.message);
    } else {
      setNewName("");
      setNewDescription("");
      setPackages(await loadPackages(sponsorId));
    }
    setAdding(false);
  }

  async function handleDelete(packageId: string) {
    const result = await supabase
      .from("sponsorship_packages")
      .delete()
      .eq("id", packageId);
    if (result.error) {
      setError(result.error.message);
      return;
    }
    setPackages((prev) => prev.filter((pkg) => pkg.id !== packageId));
  }

  if (loading)
    return (
      <div className="flex justify-center py-12">
        <div className="spinner" />
      </div>
    );

  return (
    <div className="max-w-2xl">
      <h1 className="heading-page mb-6">Packages</h1>

      <form onSubmit={handleAdd} className="card p-5 mb-6 space-y-3">
        <h2 className="heading-section">Add package</h2>
        <div className="grid grid-cols-2 gap-3">
          <input
            type="text"
            required
            placeholder="Name (e.g. Elite)"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            className="input"
          />
          <input
            type="text"
            placeholder="Description (optional)"
            value={newDescription}
            onChange={(e) => setNewDescription(e.target.value)}
            className="input"
          />
        </div>
        {error && <p className="alert-error">{error}</p>}
        <div className="flex justify-end">
          <button type="submit" disabled={adding} className="btn-primary">
            {adding ? "Adding…" : "Add package"}
          </button>
        </div>
      </form>

      {packages.length === 0 ? (
        <p className="text-sm text-gray-500">No packages yet.</p>
      ) : (
        <ul className="card divide-y divide-gray-100">
          {packages.map((pkg) => (
            <li
              key={pkg.id}
              className="flex items-center justify-between px-5 py-4"
            >
              <div>
                <p className="text-sm font-semibold text-gray-900">
                  {pkg.name}
                </p>
                {pkg.description && (
                  <p className="text-xs text-gray-500 mt-0.5">
                    {pkg.description}
                  </p>
                )}
              </div>
              <button
                onClick={() => handleDelete(pkg.id)}
                className="btn-danger-text"
              >
                Delete
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
